const jwt = require('jsonwebtoken');
const config = require('../config');
const { User } = require('../models');

const authenticate = async (req, res, next) => {
  try {
    const authHeader = req.headers.authorization;
    if (!authHeader || !authHeader.startsWith('Bearer ')) {
      return res.status(401).json({ message: 'KhÃ´ng cÃ³ token. Vui lÃ²ng Ä‘Äƒng nháº­p.' });
    }

    const token = authHeader.split(' ')[1];
    const decoded = jwt.verify(token, config.jwtSecret);

    const user = await User.findByPk(decoded.id, {
      attributes: { exclude: ['password_hash'] },
    });

    if (!user) {
      return res.status(401).json({ message: 'NgÆ°á»i dÃ¹ng khÃ´ng tá»“n táº¡i.' });
    }

    if (!user.is_active) {
      return res.status(403).json({ message: 'TÃ i khoáº£n Ä‘Ã£ bá»‹ vÃ´ hiá»‡u hÃ³a.' });
    }

    req.user = user;
    next();
  } catch (err) {
    if (err.name === 'TokenExpiredError') {
      return res.status(401).json({ message: 'Token Ä‘Ã£ háº¿t háº¡n. Vui lÃ²ng Ä‘Äƒng nháº­p láº¡i.' });
    }
    if (err.name === 'JsonWebTokenError') {
      return res.status(401).json({ message: 'Token khÃ´ng há»£p lá»‡.' });
    }
    return res.status(500).json({ message: 'Lá»—i xÃ¡c thá»±c.' });
  }
};

const authorize = (...allowedRoles) => {
  return (req, res, next) => {
    if (!req.user) {
      return res.status(401).json({ message: 'ChÆ°a xÃ¡c thá»±c.' });
    }

    if (!allowedRoles.includes(req.user.role)) {
      return res.status(403).json({
        message: `KhÃ´ng cÃ³ quyá»n truy cáº­p. Vai trÃ² yÃªu cáº§u: ${allowedRoles.join(' hoáº·c ')}.`,
      });
    }

    next();
  };
};

module.exports = { authenticate, authorize };

const errorHandler = (err, req, res, next) => {
  console.error('[ERROR]', err.stack || err.message);

  if (err.name === 'SequelizeValidationError') {
    return res.status(400).json({
      message: 'Dá»¯ liá»‡u khÃ´ng há»£p lá»‡.',
      errors: err.errors.map(e => ({ field: e.path, message: e.message })),
    });
  }

  if (err.name === 'SequelizeUniqueConstraintError') {
    return res.status(409).json({
      message: 'Dá»¯ liá»‡u Ä‘Ã£ tá»“n táº¡i (trÃ¹ng láº·p).',
      errors: err.errors.map(e => ({ field: e.path, message: e.message })),
    });
  }

  if (err.name === 'SequelizeForeignKeyConstraintError') {
    return res.status(400).json({
      message: 'Tham chiáº¿u khÃ´ng há»£p lá»‡. Dá»¯ liá»‡u liÃªn quan khÃ´ng tá»“n táº¡i.',
    });
  }

  if (err.statusCode) {
    return res.status(err.statusCode).json({ message: err.message });
  }

  res.status(500).json({ message: 'Lá»—i server ná»™i bá»™.' });
};

module.exports = { errorHandler };

