const { User } = require('../models');
const { signToken } = require('../services/auth.service');
const { AppError } = require('../utils/AppError');

const login = async (username, password) => {
  const user = await User.findOne({ where: { username } });

  if (!user) {
    throw new AppError('TÃªn Ä‘Äƒng nháº­p hoáº·c máº­t kháº©u khÃ´ng Ä‘Ãºng.', 401);
  }

  if (!user.is_active) {
    throw new AppError('TÃ i khoáº£n Ä‘Ã£ bá»‹ vÃ´ hiá»‡u hÃ³a.', 403);
  }

  const isMatch = await user.comparePassword(password);
  if (!isMatch) {
    throw new AppError('TÃªn Ä‘Äƒng nháº­p hoáº·c máº­t kháº©u khÃ´ng Ä‘Ãºng.', 401);
  }

  const token = signToken(user.id);
  const userData = user.toJSON();

  return { token, user: userData };
};

const register = async (userData) => {
  const existing = await User.findOne({ where: { username: userData.username } });
  if (existing) {
    throw new AppError('TÃªn Ä‘Äƒng nháº­p Ä‘Ã£ tá»“n táº¡i.', 409);
  }

  const existingEmail = await User.findOne({ where: { email: userData.email } });
  if (existingEmail) {
    throw new AppError('Email Ä‘Ã£ Ä‘Æ°á»£c sá»­ dá»¥ng.', 409);
  }

  const user = await User.create(userData);
  return user.toJSON();
};

const getMe = async (userId) => {
  const user = await User.findByPk(userId, {
    attributes: { exclude: ['password_hash'] },
  });
  if (!user) {
    throw new AppError('NgÆ°á»i dÃ¹ng khÃ´ng tá»“n táº¡i.', 404);
  }
  return user.toJSON();
};

module.exports = { login, register, getMe };

