const { query, transaction } = require('../config/database');
const { AppError } = require('../utils/AppError');
const { getNextCode } = require('../utils/codeGenerator');

const getAll = async (queryParams) => {
  const { warehouse_id, status, search } = queryParams;
  const where = {};
  if (warehouse_id) where.warehouse_id = parseInt(warehouse_id, 10);
  if (status) where.status = status;

  const result = await query(`
    SELECT
      io.id, io.inbound_code, io.warehouse_id, io.notes, io.status,
      io.created_by, io.approved_by,
      w.name as warehouse_name,
      u1.full_name as created_by_name,
      u2.full_name as approved_by_name,
      io.created_at, io.updated_at,
      (
        SELECT json_agg(json_build_object(
          'id', i.id,
          'product_id', i.product_id,
          'requested_quantity', i.requested_quantity,
          'assigned_location_id', i.assigned_location_id,
          'product_name', p.name,
          'product_sku', p.sku,
          'bin_code', l.bin_code
        ))
        FROM inbound_order_items i
        LEFT JOIN products p ON i.product_id = p.id
        LEFT JOIN locations l ON i.assigned_location_id = l.id
        WHERE i.inbound_order_id = io.id
      ) as items
    FROM inbound_orders io
    JOIN warehouses w ON io.warehouse_id = w.id
    LEFT JOIN users u1 ON io.created_by = u1.id
    LEFT JOIN users u2 ON io.approved_by = u2.id
    WHERE ($1::int IS NULL OR io.warehouse_id = $1)
      AND ($2::varchar IS NULL OR io.status = $2)
    ORDER BY io.created_at DESC
  `, [warehouse_id || null, status || null]);

  return result.rows;
};

const getById = async (id) => {
  const result = await query(`
    SELECT
      io.*, w.name as warehouse_name,
      u1.full_name as created_by_name,
      u2.full_name as approved_by_name
    FROM inbound_orders io
    JOIN warehouses w ON io.warehouse_id = w.id
    LEFT JOIN users u1 ON io.created_by = u1.id
    LEFT JOIN users u2 ON io.approved_by = u2.id
    WHERE io.id = $1
  `, [id]);

  if (!result.rows.length) throw new AppError('Phiáº¿u nháº­p khÃ´ng tá»“n táº¡i.', 404);

  const itemsResult = await query(`
    SELECT i.*, p.name as product_name, p.sku as product_sku, l.bin_code
    FROM inbound_order_items i
    JOIN products p ON i.product_id = p.id
    LEFT JOIN locations l ON i.assigned_location_id = l.id
    WHERE i.inbound_order_id = $1
  `, [id]);

  return { ...result.rows[0], items: itemsResult.rows };
};

const create = async (data, userId) => {
  const { warehouse_id, notes, items } = data;

  if (!warehouse_id) throw new AppError('warehouse_id lÃ  báº¯t buá»™c.', 400);
  if (!items || items.length === 0) throw new AppError('Danh sÃ¡ch sáº£n pháº©m khÃ´ng Ä‘Æ°á»£c trá»‘ng.', 400);

  const t = await transaction();

  try {
    const inboundCode = await getNextCode('INB', 'seq_inbound');

    const orderResult = await t.query(
      `INSERT INTO inbound_orders (inbound_code, warehouse_id, notes, status, created_by)
       VALUES ($1, $2, $3, 'PENDING', $4)
       RETURNING id, inbound_code`,
      [inboundCode, warehouse_id, notes || null, userId]
    );
    const orderId = orderResult.rows[0].id;

    for (const item of items) {
      if (!item.product_id || !item.requested_quantity || item.requested_quantity <= 0) {
        throw new AppError('Má»—i sáº£n pháº©m cáº§n cÃ³ product_id vÃ  requested_quantity > 0.', 400);
      }

      await t.query(
        `INSERT INTO inbound_order_items (inbound_order_id, product_id, requested_quantity)
         VALUES ($1, $2, $3)`,
        [orderId, item.product_id, item.requested_quantity]
      );
    }

    await t.commit();
    return getById(orderId);
  } catch (err) {
    await t.rollback();
    throw err;
  }
};

const approve = async (id, userId) => {
  const order = await getById(id);
  if (!order) throw new AppError('Phiáº¿u nháº­p khÃ´ng tá»“n táº¡i.', 404);
  if (order.status !== 'PENDING') throw new AppError('Chá»‰ duyá»‡t phiáº¿u Ä‘ang chá».', 400);

  const t = await transaction();

  try {
    const emptyLocations = await Location.findAll({
      where: { warehouse_id: order.warehouse_id, status: 'EMPTY' },
      order: [['zone', 'ASC'], ['aisle', 'ASC'], ['rack', 'ASC'], ['shelf', 'ASC'], ['bin', 'ASC']],
      transaction: t,
    });

    if (emptyLocations.length === 0) {
      throw new AppError('Kho khÃ´ng cÃ²n vá»‹ trÃ­ trá»‘ng nÃ o.', 400);
    }

    let locationIndex = 0;

    for (const item of order.items) {
      const suggestedLocations = [];
      let remaining = item.requested_quantity;

      while (remaining > 0 && locationIndex < emptyLocations.length) {
        const loc = emptyLocations[locationIndex];
        suggestedLocations.push({ location_id: loc.id, bin_code: loc.bin_code, qty: 1 });
        locationIndex++;
        remaining--;
      }

      if (remaining > 0) {
        throw new AppError(`KhÃ´ng Ä‘á»§ ká»‡ trá»‘ng cho sáº£n pháº©m ${item.product_name || item.product_id}.`, 400);
      }

      for (const sugg of suggestedLocations) {
        await t.query(
          `INSERT INTO inventory (product_id, warehouse_id, location_id, quantity)
           VALUES ($1, $2, $3, 1)
           ON CONFLICT (product_id, warehouse_id, location_id)
           DO UPDATE SET quantity = inventory.quantity + 1, updated_at = NOW()`,
          [item.product_id, order.warehouse_id, sugg.location_id]
        );

        await t.query(
          `UPDATE locations SET status = 'FULL', product_id = $1 WHERE id = $2`,
          [item.product_id, sugg.location_id]
        );

        const invResult = await t.query(
          `SELECT COALESCE(MAX(quantity_after), 0) + 1 as next_qty FROM inventory_transactions
           WHERE product_id = $1 AND warehouse_id = $2 AND location_id = $3`,
          [item.product_id, order.warehouse_id, sugg.location_id]
        );

        await t.query(
          `INSERT INTO inventory_transactions
           (product_id, warehouse_id, location_id, transaction_type, reference_type, reference_id, quantity_change, quantity_after, user_id)
           VALUES ($1, $2, $3, 'INBOUND', 'inbound_order', $4, 1, $5, $6)`,
          [item.product_id, order.warehouse_id, sugg.location_id, id, invResult.rows[0].next_qty, userId]
        );

        await t.query(
          `UPDATE inbound_order_items SET assigned_location_id = $1 WHERE id = $2`,
          [sugg.location_id, item.id]
        );
      }
    }

    await t.query(
      `UPDATE inbound_orders SET status = 'APPROVED', approved_by = $1, updated_at = NOW() WHERE id = $2`,
      [userId, id]
    );

    await t.commit();
    return getById(id);
  } catch (err) {
    await t.rollback();
    throw err;
  }
};

const reject = async (id, userId) => {
  const order = await getById(id);
  if (!order) throw new AppError('Phiáº¿u nháº­p khÃ´ng tá»“n táº¡i.', 404);
  if (order.status !== 'PENDING') throw new AppError('Chá»‰ tá»« chá»‘i phiáº¿u Ä‘ang chá».', 400);

  await query(
    `UPDATE inbound_orders SET status = 'REJECTED', approved_by = $1, updated_at = NOW() WHERE id = $2`,
    [userId, id]
  );

  return getById(id);
};

const suggestBins = async (warehouse_id, product_id, qty) => {
  if (!warehouse_id) throw new AppError('warehouse_id lÃ  báº¯t buá»™c.', 400);

  const result = await query(`
    SELECT id, bin_code, zone, aisle, rack, shelf, bin
    FROM locations
    WHERE warehouse_id = $1 AND status = 'EMPTY'
    ORDER BY zone ASC, aisle ASC, rack ASC, shelf ASC, bin ASC
    LIMIT $2
  `, [warehouse_id, qty || 50]);

  return {
    warehouse_id,
    total_empty: result.rowCount,
    suggestions: result.rows.map((l, i) => ({
      priority: i < 5 ? 'HIGH' : 'NORMAL',
      ...l,
    })),
  };
};

module.exports = { getAll, getById, create, approve, reject, suggestBins };

const { query } = require('../config/database');
const { AppError } = require('../utils/AppError');

const getPivotReport = async () => {
  const warehouseResult = await query(`
    SELECT id, name FROM warehouses WHERE is_active = true ORDER BY id ASC
  `);

  const warehouses = warehouseResult.rows;
  const productResult = await query(`
    SELECT id, sku, name FROM products ORDER BY name ASC
  `);

  const products = productResult.rows;
  const warehouseIds = warehouses.map(w => w.id);
  const warehouseNames = warehouses.map(w => w.name);

  const pivotResult = await query(`
    SELECT
      p.id,
      p.sku,
      p.name,
      ${warehouseIds.map((wid, i) =>
        `COALESCE(SUM(i${i}.quantity), 0) as "warehouse_${wid}"`).join(',\n')}
    FROM products p
    LEFT JOIN inventory i1 ON p.id = i1.product_id
    ${warehouseIds.slice(1).map((_, i) =>
      `LEFT JOIN inventory i${i+1} ON p.id = i${i+1}.product_id AND i${i+1}.warehouse_id = ${warehouseIds[i+1]}`).join('\n')}
    GROUP BY p.id, p.sku, p.name
    ORDER BY p.name
  `);

  return {
    warehouses: warehouseNames,
    columns: ['sku', 'name', ...warehouseIds.map(id => `warehouse_${id}`), 'total'],
    rows: pivotResult.rows.map(row => {
      const total = warehouseIds.reduce((sum, wid) => sum + parseInt(row[`warehouse_${wid}`] || 0, 10), 0);
      return { ...row, total };
    }),
  };
};

const getByWarehouse = async (warehouse_id) => {
  if (!warehouse_id) throw new AppError('warehouse_id lÃ  báº¯t buá»™c.', 400);

  const result = await query(`
    SELECT
      i.id,
      i.product_id,
      p.sku,
      p.name as product_name,
      p.unit,
      i.warehouse_id,
      w.name as warehouse_name,
      i.location_id,
      l.bin_code,
      i.quantity
    FROM inventory i
    JOIN products p ON i.product_id = p.id
    JOIN warehouses w ON i.warehouse_id = w.id
    LEFT JOIN locations l ON i.location_id = l.id
    WHERE i.warehouse_id = $1 AND i.quantity > 0
    ORDER BY p.name
  `, [warehouse_id]);

  return result.rows;
};

const getStockByProduct = async (productId) => {
  const result = await query(`
    SELECT
      i.warehouse_id,
      w.name as warehouse_name,
      COALESCE(SUM(i.quantity), 0) as total_quantity
    FROM inventory i
    JOIN warehouses w ON i.warehouse_id = w.id
    WHERE i.product_id = $1 AND i.quantity > 0
    GROUP BY i.warehouse_id, w.name
  `, [productId]);

  const grandTotal = result.rows.reduce((sum, r) => sum + parseInt(r.total_quantity, 10), 0);

  return {
    product_id: productId,
    total_stock: grandTotal,
    by_warehouse: result.rows,
  };
};

const traceProduct = async (productId) => {
  const result = await query(`
    SELECT
      l.id as location_id,
      l.bin_code,
      l.zone,
      i.warehouse_id,
      w.name as warehouse_name,
      i.quantity,
      it.quantity_change,
      it.created_at
    FROM inventory i
    JOIN locations l ON i.location_id = l.id
    JOIN warehouses w ON i.warehouse_id = w.id
    LEFT JOIN inventory_transactions it ON it.product_id = i.product_id
      AND it.location_id = i.location_id AND it.warehouse_id = i.warehouse_id
    WHERE i.product_id = $1 AND i.quantity > 0
    ORDER BY it.created_at ASC NULLS LAST
  `, [productId]);

  return result.rows;
};

module.exports = { getPivotReport, getByWarehouse, getStockByProduct, traceProduct };

const { Location, Warehouse, Product } = require('../models');
const { AppError } = require('../utils/AppError');

const getAll = async (queryParams) => {
  const { warehouse_id, status, search } = queryParams;
  const where = {};
  if (warehouse_id) where.warehouse_id = parseInt(warehouse_id, 10);
  if (status) where.status = status;
  if (search) {
    const { Op } = require('sequelize');
    where.bin_code = { [Op.iLike]: `%${search}%` };
  }
  return Location.findAll({
    where,
    include: [
      { model: Warehouse, as: 'Warehouse', attributes: ['id', 'name'] },
      { model: Product, as: 'Product', attributes: ['id', 'sku', 'name'] },
    ],
    order: [['bin_code', 'ASC']],
  });
};

const getSuggest = async (warehouse_id, product_id, qty) => {
  if (!warehouse_id) throw new AppError('warehouse_id lÃ  báº¯t buá»™c.', 400);

  const emptyLocations = await Location.findAll({
    where: { warehouse_id: parseInt(warehouse_id, 10), status: 'EMPTY' },
    order: [['zone', 'ASC'], ['aisle', 'ASC'], ['rack', 'ASC'], ['shelf', 'ASC'], ['bin', 'ASC']],
    limit: parseInt(qty, 10) || 50,
  });

  return {
    warehouse_id: parseInt(warehouse_id, 10),
    empty_bins_count: emptyLocations.length,
    suggestions: emptyLocations.map(l => ({
      location_id: l.id,
      bin_code: l.bin_code,
      zone: l.zone,
      priority: 'HIGH',
    })),
  };
};

module.exports = { getAll, getSuggest };

const { query, transaction } = require('../config/database');
const { AppError } = require('../utils/AppError');
const { getNextCode } = require('../utils/codeGenerator');

const getAll = async (queryParams) => {
  const { warehouse_id, status } = queryParams;
  const result = await query(`
    SELECT
      oo.id, oo.outbound_code, oo.warehouse_id, oo.notes, oo.status,
      oo.created_by, oo.approved_by, oo.completed_at,
      w.name as warehouse_name,
      u1.full_name as created_by_name,
      u2.full_name as approved_by_name,
      oo.created_at, oo.updated_at,
      (
        SELECT json_agg(json_build_object(
          'id', o.id,
          'product_id', o.product_id,
          'requested_quantity', o.requested_quantity,
          'picked_quantity', o.picked_quantity,
          'picked_location_id', o.picked_location_id,
          'product_name', p.name,
          'product_sku', p.sku,
          'bin_code', l.bin_code
        ))
        FROM outbound_order_items o
        LEFT JOIN products p ON o.product_id = p.id
        LEFT JOIN locations l ON o.picked_location_id = l.id
        WHERE o.outbound_order_id = oo.id
      ) as items
    FROM outbound_orders oo
    JOIN warehouses w ON oo.warehouse_id = w.id
    LEFT JOIN users u1 ON oo.created_by = u1.id
    LEFT JOIN users u2 ON oo.approved_by = u2.id
    WHERE ($1::int IS NULL OR oo.warehouse_id = $1)
      AND ($2::varchar IS NULL OR oo.status = $2)
    ORDER BY oo.created_at DESC
  `, [warehouse_id || null, status || null]);

  return result.rows;
};

const getById = async (id) => {
  const result = await query(`
    SELECT oo.*, w.name as warehouse_name,
      u1.full_name as created_by_name, u2.full_name as approved_by_name
    FROM outbound_orders oo
    JOIN warehouses w ON oo.warehouse_id = w.id
    LEFT JOIN users u1 ON oo.created_by = u1.id
    LEFT JOIN users u2 ON oo.approved_by = u2.id
    WHERE oo.id = $1
  `, [id]);

  if (!result.rows.length) throw new AppError('Phiáº¿u xuáº¥t khÃ´ng tá»“n táº¡i.', 404);

  const itemsResult = await query(`
    SELECT oi.*, p.name as product_name, p.sku as product_sku,
      l.bin_code, l.zone
    FROM outbound_order_items oi
    JOIN products p ON oi.product_id = p.id
    LEFT JOIN locations l ON oi.picked_location_id = l.id
    WHERE oi.outbound_order_id = $1
  `, [id]);

  return { ...result.rows[0], items: itemsResult.rows };
};

const create = async (data, userId) => {
  const { warehouse_id, notes, items } = data;

  if (!warehouse_id) throw new AppError('warehouse_id lÃ  báº¯t buá»™c.', 400);
  if (!items || items.length === 0) throw new AppError('Danh sÃ¡ch sáº£n pháº©m khÃ´ng Ä‘Æ°á»£c trá»‘ng.', 400);

  for (const item of items) {
    if (!item.product_id || !item.requested_quantity || item.requested_quantity <= 0) {
      throw new AppError('Má»—i sáº£n pháº©m cáº§n cÃ³ product_id vÃ  requested_quantity > 0.', 400);
    }
  }

  const t = await transaction();

  try {
    const outboundCode = await getNextCode('OTB', 'seq_outbound');

    const orderResult = await t.query(
      `INSERT INTO outbound_orders (outbound_code, warehouse_id, notes, status, created_by)
       VALUES ($1, $2, $3, 'PENDING', $4)
       RETURNING id, outbound_code`,
      [outboundCode, warehouse_id, notes || null, userId]
    );
    const orderId = orderResult.rows[0].id;

    for (const item of items) {
      await t.query(
        `INSERT INTO outbound_order_items (outbound_order_id, product_id, requested_quantity)
         VALUES ($1, $2, $3)`,
        [orderId, item.product_id, item.requested_quantity]
      );
    }

    await t.commit();
    return getById(orderId);
  } catch (err) {
    await t.rollback();
    throw err;
  }
};

const approve = async (id, userId) => {
  const order = await getById(id);
  if (!order) throw new AppError('Phiáº¿u xuáº¥t khÃ´ng tá»“n táº¡i.', 404);
  if (order.status !== 'PENDING') throw new AppError('Chá»‰ duyá»‡t phiáº¿u Ä‘ang chá».', 400);

  await query(
    `UPDATE outbound_orders SET status = 'APPROVED', approved_by = $1, updated_at = NOW() WHERE id = $2`,
    [userId, id]
  );

  return getById(id);
};

const complete = async (id, userId) => {
  const order = await getById(id);
  if (!order) throw new AppError('Phiáº¿u xuáº¥t khÃ´ng tá»“n táº¡i.', 404);
  if (order.status !== 'APPROVED') throw new AppError('Chá»‰ hoÃ n táº¥t phiáº¿u Ä‘Ã£ duyá»‡t.', 400);

  const t = await transaction();

  try {
    for (const item of order.items) {
      let remaining = item.requested_quantity;

      const binsResult = await t.query(`
        SELECT i.id as inv_id, i.location_id, i.quantity as available_qty,
          l.bin_code, l.zone
        FROM inventory i
        JOIN locations l ON i.location_id = l.id
        WHERE i.product_id = $1 AND i.warehouse_id = $2 AND i.quantity > 0
        ORDER BY i.updated_at ASC
        FOR UPDATE
      `, [item.product_id, order.warehouse_id]);

      if (binsResult.rows.length === 0) {
        throw new AppError(`Sáº£n pháº©m ${item.product_name || item.product_id} khÃ´ng cÃ³ trong kho.`, 400);
      }

      const totalAvailable = binsResult.rows.reduce((s, r) => s + parseInt(r.available_qty, 10), 0);
      if (totalAvailable < remaining) {
        throw new AppError(
          `Sáº£n pháº©m ${item.product_name || item.product_id}: chá»‰ cÃ²n ${totalAvailable}, cáº§n ${remaining}.`,
          400
        );
      }

      for (const bin of binsResult.rows) {
        if (remaining <= 0) break;

        const pickFromBin = Math.min(remaining, parseInt(bin.available_qty, 10));

        await t.query(
          `UPDATE inventory SET quantity = quantity - $1, updated_at = NOW()
           WHERE id = $2`,
          [pickFromBin, bin.inv_id]
        );

        if (parseInt(bin.available_qty, 10) - pickFromBin === 0) {
          await t.query(
            `UPDATE locations SET status = 'EMPTY', product_id = NULL WHERE id = $1`,
            [bin.location_id]
          );
        }

        const lastQtyResult = await t.query(
          `SELECT COALESCE(MAX(quantity_after), 0) as last_qty FROM inventory_transactions
           WHERE product_id = $1 AND warehouse_id = $2 AND location_id = $3`,
          [item.product_id, order.warehouse_id, bin.location_id]
        );

        await t.query(
          `INSERT INTO inventory_transactions
           (product_id, warehouse_id, location_id, transaction_type, reference_type, reference_id, quantity_change, quantity_after, user_id)
           VALUES ($1, $2, $3, 'OUTBOUND', 'outbound_order', $4, $5, $6, $7)`,
          [
            item.product_id, order.warehouse_id, bin.location_id, id,
            -pickFromBin,
            parseInt(lastQtyResult.rows[0].last_qty, 10) - pickFromBin,
            userId
          ]
        );

        await t.query(
          `UPDATE outbound_order_items SET picked_quantity = picked_quantity + $1, picked_location_id = $2 WHERE id = $3`,
          [pickFromBin, bin.location_id, item.id]
        );

        remaining -= pickFromBin;
      }
    }

    await t.query(
      `UPDATE outbound_orders SET status = 'COMPLETED', completed_at = NOW(), updated_at = NOW() WHERE id = $1`,
      [id]
    );

    await t.commit();
    return getById(id);
  } catch (err) {
    await t.rollback();
    throw err;
  }
};

const reject = async (id, userId) => {
  const order = await getById(id);
  if (!order) throw new AppError('Phiáº¿u xuáº¥t khÃ´ng tá»“n táº¡i.', 404);
  if (order.status !== 'PENDING') throw new AppError('Chá»‰ tá»« chá»‘i phiáº¿u Ä‘ang chá».', 400);

  await query(
    `UPDATE outbound_orders SET status = 'REJECTED', approved_by = $1, updated_at = NOW() WHERE id = $2`,
    [userId, id]
  );

  return getById(id);
};

module.exports = { getAll, getById, create, approve, complete, reject };

const { Product, Category } = require('../models');
const { AppError } = require('../utils/AppError');
const { getNextCode } = require('../utils/codeGenerator');

const getAll = async (queryParams) => {
  const { category_id, search } = queryParams;
  const where = {};
  if (category_id) where.category_id = category_id;
  if (search) {
    where[require('sequelize').Op.or] = [
      { name: { [require('sequelize').Op.iLike]: `%${search}%` } },
      { sku: { [require('sequelize').Op.iLike]: `%${search}%` } },
    ];
  }
  const products = await Product.findAll({
    where,
    include: [{ model: Category, as: 'Category', attributes: ['id', 'name'] }],
    order: [['id', 'ASC']],
  });
  return products.map(p => ({
    ...p.toJSON(),
    category_name: p.Category ? p.Category.name : null,
  }));
};

const getById = async (id) => {
  const product = await Product.findByPk(id, {
    include: [{ model: Category, as: 'Category', attributes: ['id', 'name'] }],
  });
  if (!product) throw new AppError('Sáº£n pháº©m khÃ´ng tá»“n táº¡i.', 404);
  return { ...product.toJSON(), category_name: product.Category ? product.Category.name : null };
};

const create = async (data) => {
  const code = await getNextCode('SP', 'seq_product');
  const product = await Product.create({ ...data, sku: code });
  return getById(product.id);
};

const updateById = async (id, data) => {
  const product = await Product.findByPk(id);
  if (!product) throw new AppError('Sáº£n pháº©m khÃ´ng tá»“n táº¡i.', 404);
  await product.update(data);
  return getById(id);
};

const deleteById = async (id) => {
  const product = await Product.findByPk(id);
  if (!product) throw new AppError('Sáº£n pháº©m khÃ´ng tá»“n táº¡i.', 404);
  await product.destroy();
};

module.exports = { getAll, getById, create, updateById, deleteById };

const { query } = require('../config/database');

const getInventorySummary = async () => {
  const result = await query(`
    SELECT
      w.id as warehouse_id, w.name as warehouse_name,
      COUNT(DISTINCT l.id) as total_bins,
      COUNT(DISTINCT l.id) FILTER (WHERE l.status = 'FULL') as used_bins,
      COUNT(DISTINCT p.id) as unique_products,
      COALESCE(SUM(i.quantity), 0) as total_quantity
    FROM warehouses w
    LEFT JOIN locations l ON l.warehouse_id = w.id
    LEFT JOIN inventory i ON i.warehouse_id = w.id
    LEFT JOIN products p ON p.id = i.product_id AND i.quantity > 0
    WHERE w.is_active = true
    GROUP BY w.id, w.name
    ORDER BY w.id
  `);
  return result.rows;
};

const getInboundSummary = async (queryParams) => {
  const { from_date, to_date } = queryParams;
  const result = await query(`
    SELECT
      w.name as warehouse_name,
      COUNT(io.id) as total_orders,
      COUNT(io.id) FILTER (WHERE io.status = 'APPROVED') as approved,
      COUNT(io.id) FILTER (WHERE io.status = 'PENDING') as pending,
      COUNT(io.id) FILTER (WHERE io.status = 'REJECTED') as rejected,
      (
        SELECT COALESCE(SUM(i.requested_quantity), 0)
        FROM inbound_order_items i
        JOIN inbound_orders io2 ON i.inbound_order_id = io2.id
        WHERE io2.warehouse_id = w.id
          AND io2.status = 'APPROVED'
          AND ($1::date IS NULL OR io2.created_at >= $1)
          AND ($2::date IS NULL OR io2.created_at <= $2)
      ) as total_items_received
    FROM warehouses w
    WHERE w.is_active = true
    GROUP BY w.id, w.name
    ORDER BY w.id
  `, [from_date || null, to_date || null]);
  return result.rows;
};

const getOutboundSummary = async (queryParams) => {
  const { from_date, to_date } = queryParams;
  const result = await query(`
    SELECT
      w.name as warehouse_name,
      COUNT(oo.id) as total_orders,
      COUNT(oo.id) FILTER (WHERE oo.status = 'COMPLETED') as completed,
      COUNT(oo.id) FILTER (WHERE oo.status = 'PENDING') as pending,
      COUNT(oo.id) FILTER (WHERE oo.status = 'APPROVED') as approved,
      COUNT(oo.id) FILTER (WHERE oo.status = 'REJECTED') as rejected,
      (
        SELECT COALESCE(SUM(oi.requested_quantity), 0)
        FROM outbound_order_items oi
        JOIN outbound_orders oo2 ON oi.outbound_order_id = oo2.id
        WHERE oo2.warehouse_id = w.id
          AND oo2.status = 'COMPLETED'
          AND ($1::date IS NULL OR oo2.created_at >= $1)
          AND ($2::date IS NULL OR oo2.created_at <= $2)
      ) as total_items_shipped
    FROM warehouses w
    WHERE w.is_active = true
    GROUP BY w.id, w.name
    ORDER BY w.id
  `, [from_date || null, to_date || null]);
  return result.rows;
};

const getSalesSummary = async (queryParams) => {
  const { from_date, to_date } = queryParams;
  const result = await query(`
    SELECT
      DATE_TRUNC('month', so.created_at) as month,
      COUNT(so.id) as total_orders,
      COUNT(so.id) FILTER (WHERE so.status = 'COMPLETED') as completed,
      COUNT(so.id) FILTER (WHERE so.status = 'PENDING') as pending,
      COALESCE(SUM(so.total_amount) FILTER (WHERE so.status = 'COMPLETED'), 0) as total_revenue
    FROM sales_orders so
    WHERE ($1::date IS NULL OR so.created_at >= $1)
      AND ($2::date IS NULL OR so.created_at <= $2)
    GROUP BY DATE_TRUNC('month', so.created_at)
    ORDER BY month DESC
    LIMIT 12
  `, [from_date || null, to_date || null]);
  return result.rows;
};

const getDashboardStats = async () => {
  const [warehouses, inventory, inbound, outbound, sales, products, customers] = await Promise.all([
    query(`SELECT COUNT(*) as count FROM warehouses WHERE is_active = true`),
    query(`SELECT COALESCE(SUM(quantity), 0) as total FROM inventory`),
    query(`SELECT COUNT(*) as count FROM inbound_orders WHERE status = 'PENDING'`),
    query(`SELECT COUNT(*) as count FROM outbound_orders WHERE status = 'PENDING'`),
    query(`SELECT COUNT(*) as count FROM sales_orders WHERE status = 'PENDING'`),
    query(`SELECT COUNT(*) as count FROM products`),
    query(`SELECT COUNT(*) as count FROM customers`),
  ]);

  return {
    total_warehouses: parseInt(warehouses.rows[0].count, 10),
    total_inventory: parseInt(inventory.rows[0].total, 10),
    pending_inbound: parseInt(inbound.rows[0].count, 10),
    pending_outbound: parseInt(outbound.rows[0].count, 10),
    pending_sales: parseInt(sales.rows[0].count, 10),
    total_products: parseInt(products.rows[0].count, 10),
    total_customers: parseInt(customers.rows[0].count, 10),
  };
};

module.exports = {
  getInventorySummary,
  getInboundSummary,
  getOutboundSummary,
  getSalesSummary,
  getDashboardStats,
};

const { query, transaction } = require('../config/database');
const { AppError } = require('../utils/AppError');
const { getNextCode } = require('../utils/codeGenerator');

const getAll = async (queryParams) => {
  const { warehouse_id, status, customer_id } = queryParams;
  const result = await query(`
    SELECT
      so.id, so.sales_order_code, so.customer_id, so.warehouse_id,
      so.total_amount, so.status, so.created_by, so.approved_by,
      c.name as customer_name, c.customer_code,
      w.name as warehouse_name,
      u1.full_name as created_by_name,
      u2.full_name as approved_by_name,
      so.created_at, so.updated_at,
      (
        SELECT json_agg(json_build_object(
          'id', si.id, 'product_id', si.product_id,
          'quantity', si.quantity, 'unit_price', si.unit_price,
          'product_name', p.name, 'product_sku', p.sku,
          'line_total', (si.quantity * si.unit_price)
        ))
        FROM sales_order_items si
        JOIN products p ON si.product_id = p.id
        WHERE si.sales_order_id = so.id
      ) as items
    FROM sales_orders so
    LEFT JOIN customers c ON so.customer_id = c.id
    LEFT JOIN warehouses w ON so.warehouse_id = w.id
    LEFT JOIN users u1 ON so.created_by = u1.id
    LEFT JOIN users u2 ON so.approved_by = u2.id
    WHERE ($1::int IS NULL OR so.warehouse_id = $1)
      AND ($2::varchar IS NULL OR so.status = $2)
      AND ($3::int IS NULL OR so.customer_id = $3)
    ORDER BY so.created_at DESC
  `, [warehouse_id || null, status || null, customer_id || null]);

  return result.rows;
};

const getById = async (id) => {
  const result = await query(`
    SELECT so.*, c.name as customer_name, c.customer_code,
      w.name as warehouse_name,
      u1.full_name as created_by_name, u2.full_name as approved_by_name
    FROM sales_orders so
    LEFT JOIN customers c ON so.customer_id = c.id
    LEFT JOIN warehouses w ON so.warehouse_id = w.id
    LEFT JOIN users u1 ON so.created_by = u1.id
    LEFT JOIN users u2 ON so.approved_by = u2.id
    WHERE so.id = $1
  `, [id]);

  if (!result.rows.length) throw new AppError('ÄÆ¡n hÃ ng khÃ´ng tá»“n táº¡i.', 404);

  const itemsResult = await query(`
    SELECT si.*, p.name as product_name, p.sku as product_sku, p.unit
    FROM sales_order_items si
    JOIN products p ON si.product_id = p.id
    WHERE si.sales_order_id = $1
  `, [id]);

  return { ...result.rows[0], items: itemsResult.rows };
};

const create = async (data, userId) => {
  const { customer_id, warehouse_id, notes, items } = data;

  if (!warehouse_id) throw new AppError('warehouse_id lÃ  báº¯t buá»™c.', 400);
  if (!items || items.length === 0) throw new AppError('Danh sÃ¡ch sáº£n pháº©m khÃ´ng Ä‘Æ°á»£c trá»‘ng.', 400);

  const t = await transaction();

  try {
    const soCode = await getNextCode('SO', 'seq_sales_order');
    let totalAmount = 0;

    for (const item of items) {
      const priceResult = await t.query(`SELECT price FROM products WHERE id = $1`, [item.product_id]);
      if (!priceResult.rows.length) throw new AppError(`Sáº£n pháº©m ID ${item.product_id} khÃ´ng tá»“n táº¡i.`, 400);
      totalAmount += parseFloat(priceResult.rows[0].price) * item.quantity;
    }

    const orderResult = await t.query(
      `INSERT INTO sales_orders (sales_order_code, customer_id, warehouse_id, notes, total_amount, status, created_by)
       VALUES ($1, $2, $3, $4, $5, 'PENDING', $6)
       RETURNING id, sales_order_code`,
      [soCode, customer_id || null, warehouse_id, notes || null, totalAmount, userId]
    );
    const orderId = orderResult.rows[0].id;

    for (const item of items) {
      const priceResult = await t.query(`SELECT price FROM products WHERE id = $1`, [item.product_id]);
      const unitPrice = parseFloat(priceResult.rows[0].price);
      await t.query(
        `INSERT INTO sales_order_items (sales_order_id, product_id, quantity, unit_price)
         VALUES ($1, $2, $3, $4)`,
        [orderId, item.product_id, item.quantity, unitPrice]
      );
    }

    await t.commit();
    return getById(orderId);
  } catch (err) {
    await t.rollback();
    throw err;
  }
};

const approve = async (id, userId) => {
  const order = await getById(id);
  if (!order) throw new AppError('ÄÆ¡n hÃ ng khÃ´ng tá»“n táº¡i.', 404);
  if (order.status !== 'PENDING') throw new AppError('Chá»‰ duyá»‡t Ä‘Æ¡n hÃ ng Ä‘ang chá».', 400);

  const t = await transaction();

  try {
    for (const item of order.items) {
      const stockResult = await t.query(`
        SELECT COALESCE(SUM(quantity), 0) as total FROM inventory
        WHERE product_id = $1 AND warehouse_id = $2
      `, [item.product_id, order.warehouse_id]);

      if (parseInt(stockResult.rows[0].total, 10) < item.quantity) {
        throw new AppError(
          `Sáº£n pháº©m ${item.product_name || item.product_id}: tá»“n kho ${stockResult.rows[0].total}, cáº§n ${item.quantity}.`,
          400
        );
      }
    }

    await t.query(
      `UPDATE sales_orders SET status = 'APPROVED', approved_by = $1, updated_at = NOW() WHERE id = $2`,
      [userId, id]
    );

    const outboundCode = await getNextCode('OTB', 'seq_outbound');
    const outboundResult = await t.query(
      `INSERT INTO outbound_orders (outbound_code, warehouse_id, notes, status, created_by)
       VALUES ($1, $2, $3, 'PENDING', $4)
       RETURNING id`,
      [outboundCode, order.warehouse_id, `Tá»± Ä‘á»™ng táº¡o tá»« SO: ${order.sales_order_code}`, userId]
    );
    const outboundId = outboundResult.rows[0].id;

    for (const item of order.items) {
      await t.query(
        `INSERT INTO outbound_order_items (outbound_order_id, product_id, requested_quantity)
         VALUES ($1, $2, $3)`,
        [outboundId, item.product_id, item.quantity]
      );
    }

    await t.query(
      `UPDATE sales_orders SET status = 'PROCESSING', updated_at = NOW() WHERE id = $1`,
      [id]
    );

    await t.commit();
    return getById(id);
  } catch (err) {
    await t.rollback();
    throw err;
  }
};

const reject = async (id, userId) => {
  const order = await getById(id);
  if (!order) throw new AppError('ÄÆ¡n hÃ ng khÃ´ng tá»“n táº¡i.', 404);
  if (order.status !== 'PENDING') throw new AppError('Chá»‰ tá»« chá»‘i Ä‘Æ¡n hÃ ng Ä‘ang chá».', 400);

  await query(
    `UPDATE sales_orders SET status = 'REJECTED', approved_by = $1, updated_at = NOW() WHERE id = $2`,
    [userId, id]
  );

  return getById(id);
};

const checkStock = async (items, warehouse_id) => {
  if (!warehouse_id) throw new AppError('warehouse_id lÃ  báº¯t buá»™c.', 400);

  const results = [];
  for (const item of items) {
    const stockResult = await query(`
      SELECT COALESCE(SUM(i.quantity), 0) as total
      FROM inventory i
      WHERE i.product_id = $1 AND i.warehouse_id = $2
    `, [item.product_id, warehouse_id]);

    const productResult = await query(`SELECT name, sku, unit, price FROM products WHERE id = $1`, [item.product_id]);

    if (productResult.rows.length) {
      results.push({
        product_id: item.product_id,
        product_name: productResult.rows[0].name,
        sku: productResult.rows[0].sku,
        unit: productResult.rows[0].unit,
        price: parseFloat(productResult.rows[0].price),
        requested: item.quantity,
        available: parseInt(stockResult.rows[0].total, 10),
        sufficient: parseInt(stockResult.rows[0].total, 10) >= item.quantity,
      });
    }
  }

  return results;
};

module.exports = { getAll, getById, create, approve, reject, checkStock };

